class Solution {
    func cutRod(_ price: [Int]) -> Int {
        let n = price.count - 1
        if n <= 0 { return 0 }
        var dp = Array(repeating: 0, count: n + 1)

        for i in 1...n {
            var maxVal = 0
            for j in 1...i {
                if j < price.count {
                    maxVal = max(maxVal, price[j] + dp[i - j])
                }
            }
            dp[i] = maxVal
        }

        return dp[n]
    }
}

