class Solution {
    func maxVowels(_ s: String, _ k: Int) -> Int {
        let vowels: Set<Character> = ["a", "e", "i", "o", "u"]
        let chars = Array(s)
        var count = 0
        for i in 0..<k {
            if vowels.contains(chars[i]) {
                count += 1
            }
        }
        var maxCount = count
        for i in k..<chars.count {
            if vowels.contains(chars[i]) {
                count += 1
            }
            if vowels.contains(chars[i - k]) {
                count -= 1
            }
            maxCount = max(maxCount, count)
        }
        return maxCount
    }
}

