class Solution {
    func groupAnagrams(_ strs: [String]) -> [[String]] {
        var groups: [String: [String]] = [:]
        for s in strs {
            let key = String(s.sorted())
            groups[key, default: []].append(s)
        }
        var result: [[String]] = []
        for (_, group) in groups {
            result.append(group.sorted())
        }
        return result.sorted { $0[0] < $1[0] }
    }
}

