class Solution {
    func nextGreaterElements(_ nums: [Int]) -> [Int] {
        var result = Array(repeating: -1, count: nums.count)
        var stack: [Int] = []
        for i in 0..<nums.count {
            while let last = stack.last, nums[last] < nums[i] {
                result[last] = nums[i]
                stack.removeLast()
            }
            stack.append(i)
        }
        return result
    }
}

