class Solution {
    func numIslands(_ grid: [[Character]]) -> Int {
        guard !grid.isEmpty, !grid[0].isEmpty else { return 0 }
        var visited = grid
        let rows = grid.count
        let cols = grid[0].count
        var count = 0

        func sink(_ r: Int, _ c: Int) {
            if r < 0 || r >= rows || c < 0 || c >= cols { return }
            if visited[r][c] != "1" { return }
            visited[r][c] = "0"
            sink(r + 1, c)
            sink(r - 1, c)
            sink(r, c + 1)
            sink(r, c - 1)
        }

        for r in 0..<rows {
            for c in 0..<cols {
                if visited[r][c] == "1" {
                    count += 1
                    sink(r, c)
                }
            }
        }
        return count
    }
}

